module top_module(
    input Clk,ShiftIn,load,ShiftEn,
    input [3:0] ParallelIn,
    output ShiftOut, 
    output [3:0] RegContent
    );reg [3:0] invalid_shift_reg;
    always @(posedge Clk)
        if(load)
            invalid_shift_reg <= ParallelIn;
        else if (ShiftEn)
            invalid_shift_reg <= {invalid_shift_reg[2:0], ShiftIn};
    assign ShiftOut = invalid_shift_reg[3];
    assign RegContent = invalid_shift_reg;
endmodule
